import{_ as e,a as o,b as t,c as r}from"./chunks/下载好后的视频.pSSnkGgz.js";import{_ as d,o as i,c as n,a2 as s}from"./chunks/framework.DnrXFDHb.js";const b=JSON.parse('{"title":"Como usar links magnet","description":"","frontmatter":{},"headers":[],"relativePath":"pt-BR/Other/magnet-transfer.md","filePath":"pt-BR/Other/magnet-transfer.md","lastUpdated":1781962217000}'),l={name:"pt-BR/Other/magnet-transfer.md"};function m(c,a,p,u,h,f){return i(),n("div",null,[...a[0]||(a[0]=[s('<h1 id="como-usar-links-magnet" tabindex="-1">Como usar links magnet <a class="header-anchor" href="#como-usar-links-magnet" aria-label="Permalink to &quot;Como usar links magnet&quot;">​</a></h1><p>O recurso de link magnet baixa os arquivos do magnet e depois envia automaticamente para o canal de armazenamento escolhido.</p><p>Ele é útil para transferir vídeos, episódios, arquivos compactados e outros conteúdos. Basta colar o magnet: o ImgBed cria uma tarefa em segundo plano e, ao final, mostra o link na lista de uploads.</p><p><img src="'+e+'" alt="Link magnet" loading="lazy"></p><h2 id="onde-usar" tabindex="-1">Onde usar <a class="header-anchor" href="#onde-usar" aria-label="Permalink to &quot;Onde usar&quot;">​</a></h2><p>A entrada fica na área de upload da página inicial.</p><p>Cole o link magnet no campo, selecione o modo <code>Transferir</code> e envie.</p><p><img src="'+o+'" alt="Upload por magnet" loading="lazy"></p><h2 id="antes-de-comecar" tabindex="-1">Antes de começar <a class="header-anchor" href="#antes-de-comecar" aria-label="Permalink to &quot;Antes de começar&quot;">​</a></h2><p>Configure primeiro a transferência por magnet no painel administrativo.</p><p>Normalmente você precisa de:</p><table tabindex="0"><thead><tr><th>Item</th><th>Para que serve</th></tr></thead><tbody><tr><td>Conta do GitHub</td><td>Executar a tarefa de download</td></tr><tr><td>Canal de upload</td><td>Google Drive, OneDrive ou outro destino final</td></tr><tr><td>Diretório de destino</td><td>Pasta onde o arquivo transferido será salvo</td></tr><tr><td>Tempo limite</td><td>Limite para tarefas demoradas</td></tr></tbody></table><h2 id="como-transferir" tabindex="-1">Como transferir <a class="header-anchor" href="#como-transferir" aria-label="Permalink to &quot;Como transferir&quot;">​</a></h2><ol><li>Cole o link magnet no campo de upload da página inicial.</li><li>Confirme que o modo está como <code>Transferir</code>.</li><li>Clique em enviar.</li><li>Aguarde a criação da tarefa.</li><li>Acompanhe o progresso na janela <code>Tarefas magnet</code>, no canto inferior direito.</li></ol><p>O download e o upload podem demorar. A velocidade depende do magnet, do ambiente de execução do GitHub e do canal de armazenamento escolhido.</p><p><img src="'+t+'" alt="Download em andamento" loading="lazy"></p><h2 id="depois-de-concluir" tabindex="-1">Depois de concluir <a class="header-anchor" href="#depois-de-concluir" aria-label="Permalink to &quot;Depois de concluir&quot;">​</a></h2><p>Quando a tarefa terminar, a lista de uploads mostra o nome do arquivo e os links.</p><p>Vídeos aparecem com prévia de vídeo; imagens aparecem com prévia de imagem; outros arquivos usam ícone genérico.</p><p><img src="'+r+'" alt="Vídeo transferido" loading="lazy"></p><p>Você pode copiar estes formatos:</p><table tabindex="0"><thead><tr><th>Formato</th><th>Uso</th></tr></thead><tbody><tr><td>Link original</td><td>Abrir o arquivo diretamente</td></tr><tr><td>Markdown</td><td>Colar em posts ou documentação Markdown</td></tr><tr><td>HTML</td><td>Inserir em código de página web</td></tr><tr><td>BBCode</td><td>Usar em fóruns compatíveis com BBCode</td></tr></tbody></table><h2 id="estados-da-tarefa" tabindex="-1">Estados da tarefa <a class="header-anchor" href="#estados-da-tarefa" aria-label="Permalink to &quot;Estados da tarefa&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Estado</th><th>Significado</th></tr></thead><tbody><tr><td>Aguardando</td><td>A tarefa foi criada e espera execução</td></tr><tr><td>Baixando</td><td>O recurso magnet está sendo baixado</td></tr><tr><td>Enviando</td><td>O arquivo baixado está sendo enviado ao canal</td></tr><tr><td>Concluído</td><td>O upload terminou e o link pode ser copiado</td></tr><tr><td>Falhou</td><td>Confira o aviso e tente novamente</td></tr></tbody></table><h2 id="dicas" tabindex="-1">Dicas <a class="header-anchor" href="#dicas" aria-label="Permalink to &quot;Dicas&quot;">​</a></h2><ul><li>Se o magnet tiver vários arquivos, o ImgBed prioriza o arquivo principal concluído.</li><li>Arquivos grandes levam mais tempo; aguarde a conclusão antes de recarregar a página.</li><li>Se o recurso não tiver fontes disponíveis, o download pode ficar lento ou falhar.</li><li>Se a conta de armazenamento não tiver cota, permissão ou diretório correto, o upload pode falhar.</li><li>A prévia de vídeo pode levar alguns segundos para carregar.</li></ul>',26)])])}const _=d(l,[["render",m]]);export{b as __pageData,_ as default};
